{"new_string": "async def _search_with_bing(self, query: str, max_results: int) -> ToolResult:
        """使用 Bing API 搜索"""
        try:
            url = "https://www.bing.com/search"
            headers = {
                "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
                "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8",
                "Accept-Language": "en-US,en;q=0.5",
            }
            params = {"q": query, "count": max_results}

            # 配置代理
            connector = None
            if PROXY_URL:
                connector = aiohttp.TCPConnector(proxy=PROXY_URL)

            async with aiohttp.ClientSession(connector=connector) as session:
                async with session.get(
                    url, 
                    params=params, 
                    headers=headers,
                    timeout=aiohttp.ClientTimeout(total=15),
                    allow_redirects=True
                ) as response:
                    if response.status == 200:
                        html = await response.text()
                        results = self._parse_bing_results(html, max_results)
                        logger.info(f"Bing 搜索成功: {query}, 找到 {len(results)} 个结果")
                        return ToolResult(success=True, result=results)
                    else:
                        return ToolResult(success=False, result=None, error=f"Bing API 返回: {response.status}")
        except Exception as e:
            logger.error(f"Bing 搜索错误: {e}")
            return ToolResult(success=False, result=None, error=str(e))

